+function detectPipeClauses(tokens: Token[]): Token[] {
+  let expectsClause = false;
+  let insideAggregate = false;
+
+  return tokens.map(token => {
+    if (token.type === TokenType.PIPE) {
+      expectsClause = true;
+      insideAggregate = false;
+      return token;
+    }
+
+    if (expectsClause && pipeClauseNames.has(token.text.toUpperCase())) {
+      const text = token.text.toUpperCase();
+      expectsClause = false;
+      insideAggregate = text === 'AGGREGATE';
+      return { ...token, type: TokenType.RESERVED_CLAUSE, text };
+    }
+
+    if (insideAggregate && token.text.toUpperCase() === 'GROUP BY') {
+      insideAggregate = false;
+      return { ...token, type: TokenType.PIPE_GROUP_BY, text: 'GROUP BY' };
+    }
+
+    return token;
+  });
